"""Symbol and instrument identity cache for Databento contract decode."""from __future__ import annotationsfrom trading_framework.infrastructure.importers.databento.instrument_cache import (    InstrumentIdentity,    InstrumentIdentityCache,)class ContractSymbolCache:    """Backward-compatible wrapper around :class:`InstrumentIdentityCache`."""    def __init__(self, *, product: str) -> None:        self._cache = InstrumentIdentityCache(product=product)    @property    def _by_symbol(self) -> dict[str, InstrumentIdentity | None]:        return self._cache._by_symbol    @property    def _by_instrument_id(self) -> dict[int, InstrumentIdentity | None]:        return self._cache._by_instrument_id    def resolve(        self,        *,        symbol: str,        instrument_id: int | None = None,    ) -> str | None:        """Return contract code for one symbol/instrument pair."""        identity = self._cache.resolve(symbol=symbol, instrument_id=instrument_id)        if identity is None:            return None        return identity.contract_code